var surah042 = {
  number: 42,
  nameArabic: "Ash-Shuraa",
  nameEnglish: "Ash-Shura",
  meaning: "The Consultation",
  totalAyahs: 53,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa Meeem", english: "Ha-Mim", romanUrdu: "Haa Meem" },
    { number: 2, arabic: "عٓسٓقٓ", transliteration: "AAaynseenqaf", transliterationB: "Ayyyn Seeen Qaaaf", english: "Ain. Sin. Qaf", romanUrdu: "Ain seen Qaaf" },
    { number: 3, arabic: "كَذَٰلِكَ يُوحِىٓ إِلَيْكَ وَإِلَى ٱلَّذِينَ مِن قَبْلِكَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Kathalika yoohee ilayka waila allatheena min qablika Allahu alAAazeezu alhakeemu", transliterationB: "Kazaalika yooheee ilaika wa ilal lazeena min qablikal laahul 'Azeezul Hakeem", english: "Thus doth (He) send inspiration to thee as (He did) to those before thee,- Allah, Exalted in Power, Full of Wisdom", romanUrdu: "Isi tarah Allah galib o hakeem (Most Mighty, the Most Wise) tumhari taraf aur tumse pehle guzre huey (Rasoolon) ki taraf wahee karta raha hai" },
    { number: 4, arabic: "لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ", transliteration: "Lahu ma fee alssamawati wama fee alardi wahuwa alAAaliyyu alAAatheemu", transliterationB: "Lahoo maa fis samaa waati wa maa fil ardi wa Huwal 'Aliyul 'Azeem", english: "To Him belongs all that is in the heavens and on earth: and He is Most High, Most Great", romanUrdu: "Aasmaano aur zameen mein jo kuch bhi hai usi ka hai, woh baratar aur azeem hai" },
    { number: 5, arabic: "تَكَادُ ٱلسَّمَٰوَٰتُ يَتَفَطَّرْنَ مِن فَوْقِهِنَّ ۚ وَٱلْمَلَٰٓئِكَةُ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيَسْتَغْفِرُونَ لِمَن فِى ٱلْأَرْضِ ۗ أَلَآ إِنَّ ٱللَّهَ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", transliteration: "Takadu alssamawatu yatafattarna min fawqihinna waalmalaikatu yusabbihoona bihamdi rabbihim wayastaghfiroona liman fee alardi ala inna Allaha huwa alghafooru alrraheemu", transliterationB: "Takaadus samaawaatu yatafattarna min fawqihinn; walmalaaa'ikatu yusabbihoona bihamdi Rabbihim wa yastaghfiroona liman fil ard; alaaa innal laaha huwal Ghafoorur Raheem", english: "The heavens are almost rent asunder from above them (by Him Glory): and the angels celebrate the Praises of their Lord, and pray for forgiveness for (all) beings on earth: Behold! Verily Allah is He, the Oft-Forgiving, Most Merciful", romanUrdu: "Qareeb hai ke aasmaan upar se phatt padein farishtey apne Rubb ki hamd ke saath uski tasbeeh kar rahey hain, aur zameen walon ke haqq mein darguzar ki darkhwastein kiye jaate hain. Aagah raho, haqeeqat mein Allah gafoor o Raheem hi hai" },
    { number: 6, arabic: "وَٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ٱللَّهُ حَفِيظٌ عَلَيْهِمْ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍۢ", transliteration: "Waallatheena ittakhathoo min doonihi awliyaa Allahu hafeethun AAalayhim wama anta AAalayhim biwakeelin", transliterationB: "Wallazeenat takhazoo min dooniheee awliyaaa'al laahu hafeezun 'alaihim wa maaa anta 'alaihim biwakeel", english: "And those who take as protectors others besides Him,- Allah doth watch over them; and thou art not the disposer of their affairs", romanUrdu: "Jin logon ne usko chodh kar apne kuch dusre sarparast bana rakkhe hain, Allah hi unpar nigraan hai, tum unke hawala daar nahin ho" },
    { number: 7, arabic: "وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ قُرْءَانًا عَرَبِيًّۭا لِّتُنذِرَ أُمَّ ٱلْقُرَىٰ وَمَنْ حَوْلَهَا وَتُنذِرَ يَوْمَ ٱلْجَمْعِ لَا رَيْبَ فِيهِ ۚ فَرِيقٌۭ فِى ٱلْجَنَّةِ وَفَرِيقٌۭ فِى ٱلسَّعِيرِ", transliteration: "Wakathalika awhayna ilayka quranan AAarabiyyan litunthira omma alqura waman hawlaha watunthira yawma aljamAAi la rayba feehi fareequn fee aljannati wafareequn fee alssaAAeeri", transliterationB: "Wa kazaalika awhainaaa llaika Qur-aanan 'Arabiyyal litunzir aUmmal Quraa wa man hawlahaa wa tunzira Yawmal Jam'ilaa raiba feeh; fareequn fil jannati wa fareequn fissa'eer", english: "Thus have We sent by inspiration to thee an Arabic Qur'an: that thou mayest warn the Mother of Cities and all around her,- and warn (them) of the Day of Assembly, of which there is no doubt: (when) some will be in the Garden, and some in the Blazing Fire", romanUrdu: "Haan, isi tarah aey Nabi, yeh Quraan e arabi humne tumhari taraf wahee (revelation) kiya hai taa-ke tum bastiyaon ke markaz (shehar e Makkah) aur uske gird o pesh rehne walon ko khabardar kardo, aur jamaa honay ke din se dara do jiske aane mein koi shakk nahin.Ek girooh ko jannat mein jaana hai aur dusre girooh ko dozakh mein" },
    { number: 8, arabic: "وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَهُمْ أُمَّةًۭ وَٰحِدَةًۭ وَلَٰكِن يُدْخِلُ مَن يَشَآءُ فِى رَحْمَتِهِۦ ۚ وَٱلظَّٰلِمُونَ مَا لَهُم مِّن وَلِىٍّۢ وَلَا نَصِيرٍ", transliteration: "Walaw shaa Allahu lajaAAalahum ommatan wahidatan walakin yudkhilu man yashao fee rahmatihi waalththalimoona ma lahum min waliyyin wala naseerin", transliterationB: "Wa law shaaa'al laahu laja'alahum ummatanw waahi datanw walaakiny yudkhilumany yashaaa'u fee rahmatih; waz zaalimoona maa lahum minw waliyyinw wa laa naseer", english: "If Allah had so willed, He could have made them a single people; but He admits whom He will to His Mercy; and the Wrong-doers will have no protector nor helper", romanUrdu: "Agar Allah chahta to in sab ko ek hi ummat bana deta, magar woh jisey chahta hai apni rehmat mein dakhil karta hai. Aur zaalimon ka na koi wali hai na madadgaar" },
    { number: 9, arabic: "أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ۖ فَٱللَّهُ هُوَ ٱلْوَلِىُّ وَهُوَ يُحْىِ ٱلْمَوْتَىٰ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Ami ittakhathoo min doonihi awliyaa faAllahu huwa alwaliyyu wahuwa yuhyee almawta wahuwa AAala kulli shayin qadeerun", transliterationB: "Amit takhazoo min dooniheee awliyaaa'a fallaahu Huwal Waliyyu wa Huwa yuhyil mawtaa wa Huwa 'alaa kulli shai'in Qadeer", english: "What! Have they taken (for worship) protectors besides Him? But it is Allah,- He is the Protector, and it is He Who gives life to the dead: It is He Who has power over all things", romanUrdu: "Kya yeh (aisey naadaan hain ke) inhon ne usey chodh kar dusre wali(protectors) bana rakkhe hain? Wali(protector) to Allah hi hai, wahi murdon (dead) ko zinda karta hai, aur woh har cheez par qadir hai" },
    { number: 10, arabic: "وَمَا ٱخْتَلَفْتُمْ فِيهِ مِن شَىْءٍۢ فَحُكْمُهُۥٓ إِلَى ٱللَّهِ ۚ ذَٰلِكُمُ ٱللَّهُ رَبِّى عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ أُنِيبُ", transliteration: "Wama ikhtalaftum feehi min shayin fahukmuhu ila Allahi thalikumu Allahu rabbee AAalayhi tawakkaltu wailayhi oneebu", transliterationB: "Wa makh-talaftum feehi min shai'in fahukmuhooo ilallaah; zaalikumul laahu Rabbee 'alaihi tawakkaltu wa ilaihi uneeb", english: "Whatever it be wherein ye differ, the decision thereof is with Allah: such is Allah my Lord: In Him I trust, and to Him I turn", romanUrdu: "Tumhare darmiyan jis maamle mein bhi ikhtilaf ho, uska faisla karna Allah ka kaam hai. Wahi Allah mera Rubb hai, usi par maine bharosa kiya, aur usi ki taraf main rujoo karta hoon" },
    { number: 11, arabic: "فَاطِرُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا وَمِنَ ٱلْأَنْعَٰمِ أَزْوَٰجًۭا ۖ يَذْرَؤُكُمْ فِيهِ ۚ لَيْسَ كَمِثْلِهِۦ شَىْءٌۭ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ", transliteration: "Fatiru alssamawati waalardi jaAAala lakum min anfusikum azwajan wamina alanAAami azwajan yathraokum feehi laysa kamithlihi shayon wahuwa alssameeAAu albaseeru", transliterationB: "Faatirus samaawaati wal ard; ja'ala lakum min anfusikum azwaajanw wa minal an'aami azwaajany yazra'ukum feeh; laisa kamislihee shai'unw wa Huwas Samee'ul Baseer", english: "(He is) the Creator of the heavens and the earth: He has made for you pairs from among yourselves, and pairs among cattle: by this means does He multiply you: there is nothing whatever like unto Him, and He is the One that hears and sees (all things)", romanUrdu: "Aasmaano aur zameen ka banane waala, jisne tumhari apni jins se tumhare liye jodey (pairs) paida kiye, aur isi tarah jaanwaron mein bhi (unhi ke hum jins) jodey(pairs) banaye, aur is tareeqe se woh tumhari naslein (generations) phailata hai. Qayanat ki koi cheez uske mushabeh nahin, woh sab kuch sunnay aur dekhne wala hai" },
    { number: 12, arabic: "لَهُۥ مَقَالِيدُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Lahu maqaleedu alssamawati waalardi yabsutu alrrizqa liman yashao wayaqdiru innahu bikulli shayin AAaleemun", transliterationB: "Lahoo maqaaleedus samaawaati wal ardi yabsutur rizqa limany yashaaa'u wa yaqdir; innahoo bikulli shai'unw wa Huwas Samee'ul Baseer", english: "To Him belong the keys of the heavens and the earth: He enlarges and restricts. The Sustenance to whom He will: for He knows full well all things", romanUrdu: "Aasmaano aur zameen ke khazano ki kunjiyan usi ke paas hain. Jisey chahta hai khula rizq deta hai aur jisey chahta hai napa tula deta hai. Usey har cheez ka ilm hai" },
    { number: 13, arabic: "۞ شَرَعَ لَكُم مِّنَ ٱلدِّينِ مَا وَصَّىٰ بِهِۦ نُوحًۭا وَٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ وَمَا وَصَّيْنَا بِهِۦٓ إِبْرَٰهِيمَ وَمُوسَىٰ وَعِيسَىٰٓ ۖ أَنْ أَقِيمُوا۟ ٱلدِّينَ وَلَا تَتَفَرَّقُوا۟ فِيهِ ۚ كَبُرَ عَلَى ٱلْمُشْرِكِينَ مَا تَدْعُوهُمْ إِلَيْهِ ۚ ٱللَّهُ يَجْتَبِىٓ إِلَيْهِ مَن يَشَآءُ وَيَهْدِىٓ إِلَيْهِ مَن يُنِيبُ", transliteration: "SharaAAa lakum mina alddeeni ma wassa bihi noohan waallathee awhayna ilayka wama wassayna bihi ibraheema wamoosa waAAeesa an aqeemoo alddeena wala tatafarraqoo feehi kabura AAala almushrikeena ma tadAAoohum ilayhi Allahu yajtabee ilayhi man yashao wayahdee ilayhi man yuneebu", transliterationB: "Shara'a lakum minad deeni maa wassaa bihee Noohanw wallazeee awhainaaa ilaika wa maa wassainaa biheee Ibraaheema wa Moosa wa 'Eesaaa an aqeemud adeena wa laa tatafarraqoo feeh; kabura 'alal mushrikeena maa tad'oohum ilaih; Allaahu yajtabee ilaihi many yashaaa'u wa yahdeee ilaihi mai yuneeb", english: "The same religion has He established for you as that which He enjoined on Noah - the which We have sent by inspiration to thee - and that which We enjoined on Abraham, Moses, and Jesus: Namely, that ye should remain steadfast in religion, and make no divisions therein: to those who worship other things than Allah, hard is the (way) to which thou callest them. Allah chooses to Himself those whom He pleases, and guides to Himself those who turn (to Him)", romanUrdu: "Usne tumhare liye deen ka wahi tareeqa muqarrar kiya hai jiska hukum usne Nooh ko diya tha, aur jisey (aey Muhammad) ab tumhari taraf humne wahee ke zariye se bheja hai, aur jiski hidayat hum Ibrahim aur Moosa aur Isa ko de chuke hain, is takeed ke saath ke qayam karo is deen ko aur us mein mutafarriq na ho jao. Yahi baat in mushrikin ko sakht nagawaar hui hai jiski taraf aey Muhammad tum inhein dawat de rahey ho. Allah jisey chahta hai apna kar leta hai, aur woh apni taraf aane ka raasta usi ko dikhata hai jo uski taraf rujoo karey" },
    { number: 14, arabic: "وَمَا تَفَرَّقُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى لَّقُضِىَ بَيْنَهُمْ ۚ وَإِنَّ ٱلَّذِينَ أُورِثُوا۟ ٱلْكِتَٰبَ مِنۢ بَعْدِهِمْ لَفِى شَكٍّۢ مِّنْهُ مُرِيبٍۢ", transliteration: "Wama tafarraqoo illa min baAAdi ma jaahumu alAAilmu baghyan baynahum walawla kalimatun sabaqat min rabbika ila ajalin musamman laqudiya baynahum wainna allatheena oorithoo alkitaba min baAAdihim lafee shakkin minhu mureebin", transliterationB: "Wa maa tafarraqooo illaa mim ba'di maa jaaa'ahumul 'ilmu baghyam bainahum; wa law laa Kalimatun sabaqat mir Rabbika ilaaa ajalim musammal laqudiya bainahum; wa innal lazeena oorisul Kitaaba mim ba'dihim lafee shakkim minhu mureeb", english: "And they became divided only after Knowledge reached them,- through selfish envy as between themselves. Had it not been for a Word that went forth before from thy Lord, (tending) to a Term appointed, the matter would have been settled between them: But truly those who have inherited the Book after them are in suspicious (disquieting) doubt concerning it", romanUrdu: "Logon mein jo tafraqa(ikhtilaf) runuma hua woh iske baad hua ke unke paas ilm aa chuka tha aur is bina par hua ke woh aapas mein ek dusre par zyadati karna chahte thay. Agar tera Rubb pehle hi yeh na farma chuka hota ke ek waqt e muqarrar tak faisla multawi rakkha jayega to inka qaziya chuka diya gaya hota. Aur haqeeqat yeh hai ke aglon ke baad jo log kitab ke waaris banaye gaye woh uski taraf se badey istarab angez shakk mein padey huey hain" },
    { number: 15, arabic: "فَلِذَٰلِكَ فَٱدْعُ ۖ وَٱسْتَقِمْ كَمَآ أُمِرْتَ ۖ وَلَا تَتَّبِعْ أَهْوَآءَهُمْ ۖ وَقُلْ ءَامَنتُ بِمَآ أَنزَلَ ٱللَّهُ مِن كِتَٰبٍۢ ۖ وَأُمِرْتُ لِأَعْدِلَ بَيْنَكُمُ ۖ ٱللَّهُ رَبُّنَا وَرَبُّكُمْ ۖ لَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ ۖ لَا حُجَّةَ بَيْنَنَا وَبَيْنَكُمُ ۖ ٱللَّهُ يَجْمَعُ بَيْنَنَا ۖ وَإِلَيْهِ ٱلْمَصِيرُ", transliteration: "Falithalika faodAAu waistaqim kama omirta wala tattabiAA ahwaahum waqul amantu bima anzala Allahu min kitabin waomirtu liaAAdila baynakum Allahu rabbuna warabbukum lana aAAmaluna walakum aAAmalukum la hujjata baynana wabaynakumu Allahu yajmaAAu baynana wailayhi almaseeru", transliterationB: "Falizaalika fad'u wastaqim kamaaa umirta wa laa tattabi' ahwaaa'ahum wa qul aamantu bimaaa anzalal laahu min Kitaab, wa umirtu li a'dila bainakum Allaahu Rabbunaa wa Rabbukum lanaaa a'maa lunaa wa lakum a'maalukim laa hujjata bainanaa wa baina kumul laahu yajma'u bainanaa wa ilaihil maseer", english: "Now then, for that (reason), call (them to the Faith), and stand steadfast as thou art commanded, nor follow thou their vain desires; but say: \"I believe in the Book which Allah has sent down; and I am commanded to judge justly between you. Allah is our Lord and your Lord: for us (is the responsibility for) our deeds, and for you for your deeds. There is no contention between us and you. Allah will bring us together, and to Him is (our) Final Goal", romanUrdu: "Junke yeh halat paida ho chuki hai isliye aey Muhammad (s.a.s.) ab tum usi deen ki taraf dawat do, aur jis tarah tumhein hukum diya gaya hai us par mazbooti ke saath qayam ho jaao, aur in logon ki khwaishat ki ittiba na karo. Aur inse kehdo ke: “Allah ne jo kitaab bhi nazil ki hai main uspar imaan laya, mujhe hukum diya gaya hai ke main tumahre darmiyan insaaf karoon. Allah hi hamara Rubb bhi hai aur tumhara Rubb bhi. Hamare aamal hamare liye hain aur tumhare aamal tumhare liye. Hamare aur tumhare darmiyan koi jhagda nahin. Allah ek roz hum sab ko jamaa karega aur usi ki taraf sab ko jana hai”" },
    { number: 16, arabic: "وَٱلَّذِينَ يُحَآجُّونَ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ٱسْتُجِيبَ لَهُۥ حُجَّتُهُمْ دَاحِضَةٌ عِندَ رَبِّهِمْ وَعَلَيْهِمْ غَضَبٌۭ وَلَهُمْ عَذَابٌۭ شَدِيدٌ", transliteration: "Waallatheena yuhajjoona fee Allahi min baAAdi ma istujeeba lahu hujjatuhum dahidatun AAinda rabbihim waAAalayhim ghadabun walahum AAathabun shadeedun", transliterationB: "Wallazeena yuhaaajjoona fil laahi mim ba'di mastujeeba lahoo hujjatuhum daahidatun 'inda Rabbihim wa 'alaihim ghadabunw wa lahum 'azaabun shadeed", english: "But those who dispute concerning Allah after He has been accepted,- futile is their dispute in the Sight of their Lord: on them will be a Penalty terrible", romanUrdu: "Allah ki dawat par labbaik kahey jaane ke baad jo log (labbaik kehne walon se) Allah ke deen ke muaamle mein jhagde karte hain, unki hujjat baazi unke Rubb ke nazdeek baatil hai, aur unpar uska gazab hai aur unke liye sakht azaab hai" },
    { number: 17, arabic: "ٱللَّهُ ٱلَّذِىٓ أَنزَلَ ٱلْكِتَٰبَ بِٱلْحَقِّ وَٱلْمِيزَانَ ۗ وَمَا يُدْرِيكَ لَعَلَّ ٱلسَّاعَةَ قَرِيبٌۭ", transliteration: "Allahu allathee anzala alkitaba bialhaqqi waalmeezani wama yudreeka laAAalla alssaAAata qareebun", transliterationB: "Allahul lazeee anzalal Kitaaba bilhaqqi wal Meezaan; wa ma yudreeka la'allas Saa'ata qareeb", english: "It is Allah Who has sent down the Book in Truth, and the Balance (by which to weigh conduct). And what will make thee realise that perhaps the Hour is close at hand", romanUrdu: "Woh Allah hi hai jisne haqq ke saath yeh kitaab aur mizaan nazil ki hai aur tumhein kya khabar, shayad ke faisley ki ghadi qareeb hi aa lagi ho" },
    { number: 18, arabic: "يَسْتَعْجِلُ بِهَا ٱلَّذِينَ لَا يُؤْمِنُونَ بِهَا ۖ وَٱلَّذِينَ ءَامَنُوا۟ مُشْفِقُونَ مِنْهَا وَيَعْلَمُونَ أَنَّهَا ٱلْحَقُّ ۗ أَلَآ إِنَّ ٱلَّذِينَ يُمَارُونَ فِى ٱلسَّاعَةِ لَفِى ضَلَٰلٍۭ بَعِيدٍ", transliteration: "YastaAAjilu biha allatheena la yuminoona biha waallatheena amanoo mushfiqoona minha wayaAAlamoona annaha alhaqqu ala inna allatheena yumaroona fee alssaAAati lafee dalalin baAAeedin", transliterationB: "Yasta'jilu bihal lazeena laa yu'minoona bihaa wallazeena aamanoo mushfiqoona minhaa wa ya'lamoona annahal haqq; alaaa innal lazeena yumaaroona fis Saa'ati lafee dalaalim ba'eed", english: "Only those wish to hasten it who believe not in it: those who believe hold it in awe, and know that it is the Truth. Behold, verily those that dispute concerning the Hour are far astray", romanUrdu: "Jo log uske aane par imaan nahin rakhte woh to us ke liye jaldi machate hain, magar jo uspar imaan rakhte hain woh ussey darte hain aur jaante hain ke yaqeenan woh aane wali hai.Khoob sunlo, jo log us ghadi ke aane mein shakk daalne wali behsain (arguments) karte hain woh gumrahi mein bahut dur nikal gaye hain" },
    { number: 19, arabic: "ٱللَّهُ لَطِيفٌۢ بِعِبَادِهِۦ يَرْزُقُ مَن يَشَآءُ ۖ وَهُوَ ٱلْقَوِىُّ ٱلْعَزِيزُ", transliteration: "Allahu lateefun biAAibadihi yarzuqu man yashao wahuwa alqawiyyu alAAazeezu", transliterationB: "Allahu lateefum bi'ibaadihee yarzuqu mai yashaaa'u wa Huwal Qawiyyul 'Azeez", english: "Gracious is Allah to His servants: He gives Sustenance to whom He pleases: and He has power and can carry out His Will", romanUrdu: "Allah apne bandon par bahut meharban hai jisey jo kuch chahta hai deta hai. Woh badi quwwat wala aur zabardast hai" },
    { number: 20, arabic: "مَن كَانَ يُرِيدُ حَرْثَ ٱلْءَاخِرَةِ نَزِدْ لَهُۥ فِى حَرْثِهِۦ ۖ وَمَن كَانَ يُرِيدُ حَرْثَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَا لَهُۥ فِى ٱلْءَاخِرَةِ مِن نَّصِيبٍ", transliteration: "Man kana yureedu hartha alakhirati nazid lahu fee harthihi waman kana yureedu hartha alddunya nutihi minha wama lahu fee alakhirati min naseebin", transliterationB: "Man kaana yureedu harsal Aakhirati nazid lahoo fee harsihee wa man kaana yureedu harsad dunyaa nu'tihee mnhaa wa maa lahoo fil Aakhirati min naseeb", english: "To any that desires the tilth of the Hereafter, We give increase in his tilth, and to any that desires the tilth of this world, We grant somewhat thereof, but he has no share or lot in the Hereafter", romanUrdu: "Jo koi aakhirat ki kheti chahta hai uski kheti ko hum badhate hain, aur jo duniya ki kheti chahta hai usey duniya hi mein se detay hain magar aakhirat mein uska koi hissa nahin hai" },
    { number: 21, arabic: "أَمْ لَهُمْ شُرَكَٰٓؤُا۟ شَرَعُوا۟ لَهُم مِّنَ ٱلدِّينِ مَا لَمْ يَأْذَنۢ بِهِ ٱللَّهُ ۚ وَلَوْلَا كَلِمَةُ ٱلْفَصْلِ لَقُضِىَ بَيْنَهُمْ ۗ وَإِنَّ ٱلظَّٰلِمِينَ لَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Am lahum shurakao sharaAAoo lahum mina alddeeni ma lam yathan bihi Allahu walawla kalimatu alfasli laqudiya baynahum wainna alththalimeena lahum AAathabun aleemun", transliterationB: "Am lahum shurakaaa'u shara'oo lahum minad deeni maa lam yaazam bihil laah; wa law laa kalimatul fasli laqudiya bainahum; wa innaz zaalimeena lahum 'azaabun aleem", english: "What! have they partners (in godhead), who have established for them some religion without the permission of Allah? Had it not been for the Decree of Judgment, the matter would have been decided between them (at once). But verily the Wrong-doers will have a grievous Penalty", romanUrdu: "Kya yeh log kuch aisey sharik e khuda rakhte hain jinhon ne inke liye deen ki noiyat rakhne wala ek aisa tareeka muqarrar kardiya hai jiska Allah ne izan nahin diya? Agar faislay ki baat pehle tai na ho gayi hoti to inka qaziya chuka diya gaya hota. Yaqeenan in zaalimon ke liye dardnaak azaab hai" },
    { number: 22, arabic: "تَرَى ٱلظَّٰلِمِينَ مُشْفِقِينَ مِمَّا كَسَبُوا۟ وَهُوَ وَاقِعٌۢ بِهِمْ ۗ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فِى رَوْضَاتِ ٱلْجَنَّاتِ ۖ لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْ ۚ ذَٰلِكَ هُوَ ٱلْفَضْلُ ٱلْكَبِيرُ", transliteration: "Tara alththalimeena mushfiqeena mimma kasaboo wahuwa waqiAAun bihim waallatheena amanoo waAAamiloo alssalihati fee rawdati aljannati lahum ma yashaoona AAinda rabbihim thalika huwa alfadlu alkabeeru", transliterationB: "Taraz zaalimeena mushfiqeena mimmaa kasaboo wa huwa waaqi'um bihim; wallazeena aamanoo wa 'amilus saalihaati fee rawdaatil jannaati lahum maa yashaaa'oona 'inda Rabbihim; zaalika huwal fadlul kabeer", english: "Thou wilt see the Wrong-doers in fear on account of what they have earned, and (the burden of) that must (necessarily) fall on them. But those who believe and work righteous deeds will be in the luxuriant meads of the Gardens: they shall have, before their Lord, all that they wish for. That will indeed be the magnificent Bounty (of Allah)", romanUrdu: "Tum dekhoge ke yeh zaalim us waqt apne kiye ke anjaam se darr rahey hongey aur woh inpar aa kar rahega. Ba-khilaf iske jo log imaan le aaye hain aur jinhon ne neik aamal kiye hain woh jannat ke gulistano mein honge, jo kuch bhi woh chahenge apne Rubb ke haan paayenge, yahi bada fazal hai" },
    { number: 23, arabic: "ذَٰلِكَ ٱلَّذِى يُبَشِّرُ ٱللَّهُ عِبَادَهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ ۗ قُل لَّآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا إِلَّا ٱلْمَوَدَّةَ فِى ٱلْقُرْبَىٰ ۗ وَمَن يَقْتَرِفْ حَسَنَةًۭ نَّزِدْ لَهُۥ فِيهَا حُسْنًا ۚ إِنَّ ٱللَّهَ غَفُورٌۭ شَكُورٌ", transliteration: "Thalika allathee yubashshiru Allahu AAibadahu allatheena amanoo waAAamiloo alssalihati qul la asalukum AAalayhi ajran illa almawaddata fee alqurba waman yaqtarif hasanatan nazid lahu feeha husnan inna Allaha ghafoorun shakoorun", transliterationB: "Zaalikal lazee yubash shirul laahu 'ibaadahul lazeena aamanoo wa 'amilus saalihaat; qul laaa as'alukum 'alaihi ajran illal mawaddata fil qurbaa; wa mai yaqtarif hasanatan nazid lahoo feehaa husnaa; innal laaha Ghafoorun Shakoor", english: "That is (the Bounty) whereof Allah gives Glad Tidings to His Servants who believe and do righteous deeds. Say: \"No reward do I ask of you for this except the love of those near of kin.\" And if any one earns any good, We shall give him an increase of good in respect thereof: for Allah is Oft-Forgiving, Most Ready to appreciate (service)", romanUrdu: "Yeh hai woh cheez jiski khush khabri Allah apne un bandon ko deta hai jinhon ne maan liya aur neik amal kiye. Aey Nabi, in logon se kehdo ke main is kaam par tumse kisi ajar ka taalib nahin hoon. Albatta qarabat (kinsfolk) ki muhabbat zaroor chahta hoon. Jo koi bhalayi kamayega hum uske liye us bhalayi mein khoobi ka izafa kar dengey. Beshak Allah bada darguzar karne wala aur qadardaan hai" },
    { number: 24, arabic: "أَمْ يَقُولُونَ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًۭا ۖ فَإِن يَشَإِ ٱللَّهُ يَخْتِمْ عَلَىٰ قَلْبِكَ ۗ وَيَمْحُ ٱللَّهُ ٱلْبَٰطِلَ وَيُحِقُّ ٱلْحَقَّ بِكَلِمَٰتِهِۦٓ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Am yaqooloona iftara AAala Allahi kathiban fain yashai Allahu yakhtim AAala qalbika wayamhu Allahu albatila wayuhiqqu alhaqqa bikalimatihi innahu AAaleemun bithati alssudoori", transliterationB: "Am yaqooloonaf tara 'alal laahi kaziban fa-iny yasha il laahu yakhtim 'alaa qalbik; wa yamhul laahul baatila wa yuhiqqul haqqa bi Kalimaatih; innahoo 'Aleemum bizaatis sudoor", english: "What! Do they say, \"He has forged a falsehood against Allah\"? But if Allah willed, He could seal up thy heart. And Allah blots out Vanity, and proves the Truth by His Words. For He knows well the secrets of all hearts", romanUrdu: "Kya yeh log kehte hain ke is shaks ne Allah par jhoota bohtan ghadh liya hai? Agar Allah chahe to tumhare dil par mohar karde. Woh baatil ko mita deta hai aur haq ko apne farmaano se haqq kar dikhata hai. Woh seeno ke chupey huey raaz jaanta hai" },
    { number: 25, arabic: "وَهُوَ ٱلَّذِى يَقْبَلُ ٱلتَّوْبَةَ عَنْ عِبَادِهِۦ وَيَعْفُوا۟ عَنِ ٱلسَّيِّـَٔاتِ وَيَعْلَمُ مَا تَفْعَلُونَ", transliteration: "Wahuwa allathee yaqbalu alttawbata AAan AAibadihi wayaAAfoo AAani alssayyiati wayaAAlamu ma tafAAaloona", transliterationB: "Wa Huwal lazee yaqbalut tawbata 'an 'ibaadihee wa ya'foo 'anis saiyiaati wa ya'lamu maa taf'aloon", english: "He is the One that accepts repentance from His Servants and forgives sins: and He knows all that ye do", romanUrdu: "Wahi hai jo apne bandon se tawbah qabool karta hai aur buraiyon se darguzar karta hai, halanke tum logon ke sab afaal (jo kuch kar rahe ho) ka usey ilm hai" },
    { number: 26, arabic: "وَيَسْتَجِيبُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَيَزِيدُهُم مِّن فَضْلِهِۦ ۚ وَٱلْكَٰفِرُونَ لَهُمْ عَذَابٌۭ شَدِيدٌۭ", transliteration: "Wayastajeebu allatheena amanoo waAAamiloo alssalihati wayazeeduhum min fadlihi waalkafiroona lahum AAathabun shadeedun", transliterationB: "Wa yastajeebul lazeena aamanoo wa 'amilu saalihaati wa yazeeduhum min fadlih; wal kaafiroona lahum 'azaabun shadeed", english: "And He listens to those who believe and do deeds of righteousness, and gives them increase of His Bounty: but for the Unbelievers their is a terrible Penalty", romanUrdu: "Woh imaan laane walon aur neik amal karne waalon ki dua qabool karta hai aur apne fazal se unko aur zyada deta hai. Rahey inkar karne walay, to unke liye dardnaak saza hai" },
    { number: 27, arabic: "۞ وَلَوْ بَسَطَ ٱللَّهُ ٱلرِّزْقَ لِعِبَادِهِۦ لَبَغَوْا۟ فِى ٱلْأَرْضِ وَلَٰكِن يُنَزِّلُ بِقَدَرٍۢ مَّا يَشَآءُ ۚ إِنَّهُۥ بِعِبَادِهِۦ خَبِيرٌۢ بَصِيرٌۭ", transliteration: "Walaw basata Allahu alrrizqa liAAibadihi labaghaw fee alardi walakin yunazzilu biqadarin ma yashao innahu biAAibadihi khabeerun baseerun", transliterationB: "Wa law basatal laahur rizqa li'ibaadihee labaghaw fil ardi wa laakiny yunazzilu biqadarim maa yashaaa'; innahoo bi'ibaadihee Khabeerum Baseer", english: "If Allah were to enlarge the provision for His Servants, they would indeed transgress beyond all bounds through the earth; but he sends (it) down in due measure as He pleases. For He is with His Servants Well-acquainted, Watchful", romanUrdu: "Agar Allah apne sab bandon(servants) ko khula rizq de deta to woh zameen mein sarkashi ka toofaan barpa kar detey, Magar woh ek hisaab se jitna chahta hai naazil karta hai, yaqeenan woh apne bandon se ba khabar hai aur un par nigaah rakhta hai" },
    { number: 28, arabic: "وَهُوَ ٱلَّذِى يُنَزِّلُ ٱلْغَيْثَ مِنۢ بَعْدِ مَا قَنَطُوا۟ وَيَنشُرُ رَحْمَتَهُۥ ۚ وَهُوَ ٱلْوَلِىُّ ٱلْحَمِيدُ", transliteration: "Wahuwa allathee yunazzilu alghaytha min baAAdi ma qanatoo wayanshuru rahmatahu wahuwa alwaliyyu alhameedu", transliterationB: "Wa Huwal lazee yunazzilul ghaisa mim ba'di maa qanatoo wa yanshuru rahmatah; wa Huwal Waliyyul Hameed", english: "He is the One that sends down rain (even) after (men) have given up all hope, and scatters His Mercy (far and wide). And He is the Protector, Worthy of all Praise", romanUrdu: "Wahi hai jo logon ke mayous ho janey ke baad meh (rain) barsata hai aur apni rehmat phaila deta hai, aur wahi qaabil e taareef wali hai" },
    { number: 29, arabic: "وَمِنْ ءَايَٰتِهِۦ خَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَثَّ فِيهِمَا مِن دَآبَّةٍۢ ۚ وَهُوَ عَلَىٰ جَمْعِهِمْ إِذَا يَشَآءُ قَدِيرٌۭ", transliteration: "Wamin ayatihi khalqu alssamawati waalardi wama baththa feehima min dabbatin wahuwa AAala jamAAihim itha yashao qadeerun", transliterationB: "Wa min Aayaatihee khalqus samaawaati wal ardi wa maa bassa feehimaa min daaabbah; wa Huwa 'alaa jam'ihim izaa yashaaa'u Qadeer", english: "And among His Signs is the creation of the heavens and the earth, and the living creatures that He has scattered through them: and He has power to gather them together when He wills", romanUrdu: "Uski nishaniyon mein se hai yeh zameen aur aasmaano ki paidaish, aur yeh jaandaar makhlooqat jo usne dono jagah phayla rakkhi hain. Woh jab chahey inhein ikattha kar sakta hai" },
    { number: 30, arabic: "وَمَآ أَصَٰبَكُم مِّن مُّصِيبَةٍۢ فَبِمَا كَسَبَتْ أَيْدِيكُمْ وَيَعْفُوا۟ عَن كَثِيرٍۢ", transliteration: "Wama asabakum min museebatin fabima kasabat aydeekum wayaAAfoo AAan katheerin", transliterationB: "Wa maaa asaabakum mim museebatin fabimaa kasabat aydeekum wa ya'foo 'an kaseer", english: "Whatever misfortune happens to you, is because on the things your hands have wrought, and for many (of them) He grants forgiveness", romanUrdu: "Tumpar jo musibat bhi aayi hai, tumhare apne haathon ki kamayi se aayi hai, aur bahut se kasooron se woh waise hi darguzar kar jaata hai" },
    { number: 31, arabic: "وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍۢ", transliteration: "Wama antum bimuAAjizeena fee alardi wama lakum min dooni Allahi min waliyyin wala naseerin", transliterationB: "Wa maaa antum bimu'jizeena fil ardi wa maa lakum min doonil laahi minw wa liyyinw wa laa naseer", english: "Nor can ye frustrate (aught), (fleeing) through the earth; nor have ye, besides Allah, any one to protect or to help", romanUrdu: "Tum zameen mein apne khuda ko aajiz (frustrate) kardene waley nahin ho, aur Allah ke muqable mein tum koi haami o naasir (protector or helper) nahin rakhte" },
    { number: 32, arabic: "وَمِنْ ءَايَٰتِهِ ٱلْجَوَارِ فِى ٱلْبَحْرِ كَٱلْأَعْلَٰمِ", transliteration: "Wamin ayatihi aljawari fee albahri kaalaAAlami", transliterationB: "Wa min Aayaatihil ja waarifil bahri kal a'lam", english: "And among His Signs are the ships, smooth-running through the ocean, (tall) as mountains", romanUrdu: "Uski nishaniyon mein se hain yeh jahaz (ships) jo samandar mein pahadon ki tarah nazar aate hain" },
    { number: 33, arabic: "إِن يَشَأْ يُسْكِنِ ٱلرِّيحَ فَيَظْلَلْنَ رَوَاكِدَ عَلَىٰ ظَهْرِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍ", transliteration: "In yasha yuskini alrreeha fayathlalna rawakida AAala thahrihi inna fee thalika laayatin likulli sabbarin shakoorin", transliterationB: "Iny yashaaa yuskinir reeha fa yazlalna rawaakida 'alaa zahirh; inna fee zaalika la Aayaatil likulli sabbaarin shakoor", english: "If it be His Will He can still the Wind: then would they become motionless on the back of the (ocean). Verily in this are Signs for everyone who patiently perseveres and is grateful", romanUrdu: "Allah jab chahey hawa ko saakin (motionless) karde aur yeh samandar ki peeth (back) par khade reh jayein. Ismein badi nishaniyan hain har us shaks ke liye jo kamal darja sabr o shukar karne wala ho" },
    { number: 34, arabic: "أَوْ يُوبِقْهُنَّ بِمَا كَسَبُوا۟ وَيَعْفُ عَن كَثِيرٍۢ", transliteration: "Aw yoobiqhunna bima kasaboo wayaAAfu AAan katheerin", transliterationB: "Aw yoobiqhunna bimaa kasaboo wa ya'fu 'an kaseer", english: "Or He can cause them to perish because of the (evil) which (the men) have earned; but much doth He forgive", romanUrdu: "Ya (unpar sawar honay walon ke) bahut se gunahon se dar guzar karte huey unke chandh hi kartooton ki padash mein unhein dubo (drown) de" },
    { number: 35, arabic: "وَيَعْلَمَ ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِنَا مَا لَهُم مِّن مَّحِيصٍۢ", transliteration: "WayaAAlama allatheena yujadiloona fee ayatina ma lahum min maheesin", transliterationB: "Wa ya'lamal lazeena yujaadiloona feee Aayaatinaa maa lahum mim mahees", english: "But let those know, who dispute about Our Signs, that there is for them no way of escape", romanUrdu: "Aur us waqt hamari aayat mein jhagade karne walon ko pata chal jaaye ke unke liye koi jaaye panaah nahin hai" },
    { number: 36, arabic: "فَمَآ أُوتِيتُم مِّن شَىْءٍۢ فَمَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ وَأَبْقَىٰ لِلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", transliteration: "Fama ooteetum min shayin famataAAu alhayati alddunya wama AAinda Allahi khayrun waabqa lillatheena amanoo waAAala rabbihim yatawakkaloona", transliterationB: "Famaa ooteetum min shai'in famataa'ul hayaatid dunyaa wa maa 'indal laahi khairunw wa abqaa lillazeena aamanoo wa 'alaa Rabbihim yatawakkaloon", english: "Whatever ye are given (here) is (but) a convenience of this life: but that which is with Allah is better and more lasting: (it is) for those who believe and put their trust in their Lord", romanUrdu: "Jo kuch bhi tum logon ko diya gaya hai woh mehaz duniya ki chand roza zindagi ka sar o saaman hai, aur jo kuch Allah ke haan hai woh behtar bhi hai aur payedar bhi. Woh un logon ke liye hai jo imaan laye hain aur apne Rubb par bharosa karte hain" },
    { number: 37, arabic: "وَٱلَّذِينَ يَجْتَنِبُونَ كَبَٰٓئِرَ ٱلْإِثْمِ وَٱلْفَوَٰحِشَ وَإِذَا مَا غَضِبُوا۟ هُمْ يَغْفِرُونَ", transliteration: "Waallatheena yajtaniboona kabaira alithmi waalfawahisha waitha ma ghadiboo hum yaghfiroona", transliterationB: "Wallazeena yajtaniboona kabaaa'iral ismi wal fawaa hisha wa izaa maa ghadiboo hum yaghfiroon", english: "Those who avoid the greater crimes and shameful deeds, and, when they are angry even then forgive", romanUrdu: "Jo badey badey gunahon aur be hayayi ke kaamon se parheiz karte hain aur agar gussa aa jaye to darguzar kar jatey hain" },
    { number: 38, arabic: "وَٱلَّذِينَ ٱسْتَجَابُوا۟ لِرَبِّهِمْ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَمْرُهُمْ شُورَىٰ بَيْنَهُمْ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ", transliteration: "Waallatheena istajaboo lirabbihim waaqamoo alssalata waamruhum shoora baynahum wamimma razaqnahum yunfiqoona", transliterationB: "Wallazeenas tajaaboo li Rabbhim wa aqaamus Salaata wa amruhum shooraa bainahum wa mimmaa razaqnaahum yunfiqoon", english: "Those who hearken to their Lord, and establish regular Prayer; who (conduct) their affairs by mutual Consultation; who spend out of what We bestow on them for Sustenance", romanUrdu: "Jo apne Rubb ka hukum maante hain, namaz qayam karte hain, apne maamlaat aapas ke mashware se chalate hain, humne jo kuch bhi rizq unhein diya hai us mein se kharch karte hain" },
    { number: 39, arabic: "وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلْبَغْىُ هُمْ يَنتَصِرُونَ", transliteration: "Waallatheena itha asabahumu albaghyu hum yantasiroona", transliterationB: "Wallazeena izaa asaabahumul baghyu hum yantasiroon", english: "And those who, when an oppressive wrong is inflicted on them, (are not cowed but) help and defend themselves", romanUrdu: "Aur jab unpar zyadati ki jaati hai to uska muqaabla karte hain" },
    { number: 40, arabic: "وَجَزَٰٓؤُا۟ سَيِّئَةٍۢ سَيِّئَةٌۭ مِّثْلُهَا ۖ فَمَنْ عَفَا وَأَصْلَحَ فَأَجْرُهُۥ عَلَى ٱللَّهِ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلظَّٰلِمِينَ", transliteration: "Wajazao sayyiatin sayyiatun mithluha faman AAafa waaslaha faajruhu AAala Allahi innahu la yuhibbu alththalimeena", transliterationB: "Wa jazaaa'u saiyi'atin saiyi'tum misluha faman 'afaa wa aslaha fa ajruhoo 'alal laah; innahoo laa yuhibbuz zaalimeen", english: "The recompense for an injury is an injury equal thereto (in degree): but if a person forgives and makes reconciliation, his reward is due from Allah: for (Allah) loveth not those who do wrong", romanUrdu: "Burayi ka badla waisi hi burayi hai, phir jo koi maaf karde aur islaah karey uska ajar Allah ke zimme hai. Allah zaalimon ko pasand nahin karta" },
    { number: 41, arabic: "وَلَمَنِ ٱنتَصَرَ بَعْدَ ظُلْمِهِۦ فَأُو۟لَٰٓئِكَ مَا عَلَيْهِم مِّن سَبِيلٍ", transliteration: "Walamani intasara baAAda thulmihi faolaika ma AAalayhim min sabeelin", transliterationB: "Wa lamanin tasara ba'da zulmihee fa ulaaa'ika maa 'alaihim min sabeel", english: "But indeed if any do help and defend themselves after a wrong (done) to them, against such there is no cause of blame", romanUrdu: "Aur jo log zulm honay ke baad badla lein unko malamat nahin ki ja sakti" },
    { number: 42, arabic: "إِنَّمَا ٱلسَّبِيلُ عَلَى ٱلَّذِينَ يَظْلِمُونَ ٱلنَّاسَ وَيَبْغُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Innama alssabeelu AAala allatheena yathlimoona alnnasa wayabghoona fee alardi bighayri alhaqqi olaika lahum AAathabun aleemun", transliterationB: "Innamas sabeelu 'alal lazeena yazlimoonan naasa wa yabghoona fil ardi bighairil haqq; ulaaa'ika lahum 'azaabun aleem", english: "The blame is only against those who oppress men and wrong-doing and insolently transgress beyond bounds through the land, defying right and justice: for such there will be a penalty grievous", romanUrdu: "Malamat ke mustahiq to woh hain jo dusron par zulm karte hain aur zameen mein na haqq zyadatiyan karte hain. Aisey logon ke liye dardnaak azaab hai" },
    { number: 43, arabic: "وَلَمَن صَبَرَ وَغَفَرَ إِنَّ ذَٰلِكَ لَمِنْ عَزْمِ ٱلْأُمُورِ", transliteration: "Walaman sabara waghafara inna thalika lamin AAazmi alomoori", transliterationB: "Wa laman sabara wa ghafara inna zaalika lamin 'azmil umoor", english: "But indeed if any show patience and forgive, that would truly be an exercise of courageous will and resolution in the conduct of affairs", romanUrdu: "Albatta jo shaks sabr se kaam le aur darguzar karey, to yeh badi ulul azmi ke kaamon mein se hai" },
    { number: 44, arabic: "وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن وَلِىٍّۢ مِّنۢ بَعْدِهِۦ ۗ وَتَرَى ٱلظَّٰلِمِينَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ يَقُولُونَ هَلْ إِلَىٰ مَرَدٍّۢ مِّن سَبِيلٍۢ", transliteration: "Waman yudlili Allahu fama lahu min waliyyin min baAAdihi watara alththalimeena lamma raawoo alAAathaba yaqooloona hal ila maraddin min sabeelin", transliterationB: "Wa mai yudlilil laahu famaa lahoo minw waliyyim mim ba'dih; wa taraz zaalimeena lammaa ra awul 'azaaba yaqooloona hal ilaa maraddim min sabeel", english: "For any whom Allah leaves astray, there is no protector thereafter. And thou wilt see the Wrong-doers, when in sight of the Penalty, Say: \"Is there any way (to effect) a return", romanUrdu: "Jis ko Allah hi gumraahi mein phenk de us ka koi sambhaalne wala Allah ke baad nahin hai. Tum dekho ge yeh zaalim jab azaab dekhenge to kahenge ab palatne ki bhi koi sabeel hai" },
    { number: 45, arabic: "وَتَرَىٰهُمْ يُعْرَضُونَ عَلَيْهَا خَٰشِعِينَ مِنَ ٱلذُّلِّ يَنظُرُونَ مِن طَرْفٍ خَفِىٍّۢ ۗ وَقَالَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ ٱلْخَٰسِرِينَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ أَلَآ إِنَّ ٱلظَّٰلِمِينَ فِى عَذَابٍۢ مُّقِيمٍۢ", transliteration: "Watarahum yuAAradoona AAalayha khashiAAeena mina alththulli yanthuroona min tarfin khafiyyin waqala allatheena amanoo inna alkhasireena allatheena khasiroo anfusahum waahleehim yawma alqiyamati ala inna alththalimeena fee AAathabin muqeemin", transliterationB: "Wa taraahum yu'radoona 'alaihaa khaashi'eena minazzulli yanzuroona min tarfin khaifiyy; wa qaalal lazeena aamanooo innal khaasireenal lazeena khasiroon anfusahum wa ahleehim Yawmal Qiyaamah; alaaa innaz zaalimeena fee'azaabim muqeem", english: "And thou wilt see them brought forward to the (Penalty), in a humble frame of mind because of (their) disgrace, (and) looking with a stealthy glance. And the Believers will say: \"Those are indeed in loss, who have given to perdition their own selves and those belonging to them on the Day of Judgment. Behold! Truly the Wrong-doers are in a lasting Penalty", romanUrdu: "Aur tum dekhoge ke yeh jahannum ke saamne jab laye jayenge to zillat ke maare jhuke jaa rahey hongey aur usko nazar bacha bacha kar kan aankiyon (covert glance) se dekhenge.Us waqt woh log jo iman laye thay kahenge ke waqai asal ziyan kaar ([true] losers) wahi hain jinhon ne aaj qayamat ke din apne aapko aur apne mutaaliqin ko khasare mein daal diya. Khabardar raho, zaalim log mustaqil azaab mein hongey" },
    { number: 46, arabic: "وَمَا كَانَ لَهُم مِّنْ أَوْلِيَآءَ يَنصُرُونَهُم مِّن دُونِ ٱللَّهِ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن سَبِيلٍ", transliteration: "Wama kana lahum min awliyaa yansuroonahum min dooni Allahi waman yudlili Allahu fama lahu min sabeelin", transliterationB: "Wa maa kaana lahum min awliyaaa'a yansuroonahum min doonil laah; wa mai yudlilil laahu famaa lahoo min sabeel", english: "And no protectors have they to help them, other than Allah. And for any whom Allah leaves to stray, there is no way (to the Goal)", romanUrdu: "Aur unke koi haami o sarparast na hongey jo Allah ke muqaable mein unki madad ko aayein. Jisey Allah gumraahi mein phenk de uske liye bachao ki koi sabeel nahin" },
    { number: 47, arabic: "ٱسْتَجِيبُوا۟ لِرَبِّكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۚ مَا لَكُم مِّن مَّلْجَإٍۢ يَوْمَئِذٍۢ وَمَا لَكُم مِّن نَّكِيرٍۢ", transliteration: "Istajeeboo lirabbikum min qabli an yatiya yawmun la maradda lahu mina Allahi ma lakum min maljain yawmaithin wama lakum min nakeerin", transliterationB: "Istajeeboo li Rabbikum min qabli any yaatiya Yawmul laa maradda lahoo minal laah; maa lakum mim malja iny yawma'izinw wa maa lakum min nakeer", english: "Hearken ye to your Lord, before there come a Day which there will be no putting back, because of (the Ordainment of) Allah! that Day there will be for you no place of refuge nor will there be for you any room for denial (of your sins)", romanUrdu: "Maan lo apne Rubb ki baat qabl iske ke woh din aaye jiske talne ki koi surat Allah ki taraf se nahin hai. Us din tumhare liye koi jaaye panaah na hogi aur na koi tumhare haal ko badalne ki koshish karne wala hoga" },
    { number: 48, arabic: "فَإِنْ أَعْرَضُوا۟ فَمَآ أَرْسَلْنَٰكَ عَلَيْهِمْ حَفِيظًا ۖ إِنْ عَلَيْكَ إِلَّا ٱلْبَلَٰغُ ۗ وَإِنَّآ إِذَآ أَذَقْنَا ٱلْإِنسَٰنَ مِنَّا رَحْمَةًۭ فَرِحَ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَإِنَّ ٱلْإِنسَٰنَ كَفُورٌۭ", transliteration: "Fain aAAradoo fama arsalnaka AAalayhim hafeethan in AAalayka illa albalaghu wainna itha athaqna alinsana minna rahmatan fariha biha wain tusibhum sayyiatun bima qaddamat aydeehim fainna alinsana kafoorun", transliterationB: "Fa-in a'radoo famaaa arsalnaaka 'alaihim hafeezan in 'alaika illal balaagh; wa innaaa izaaa azaqnal insaana minnaa rahmatan fariha bihaa wa in tusibhum saiyi'atum bimaa qaddamat aydeehim fa innal insaana kafoor", english: "If then they run away, We have not sent thee as a guard over them. Thy duty is but to convey (the Message). And truly, when We give man a taste of a Mercy from Ourselves, he doth exult thereat, but when some ill happens to him, on account of the deeds which his hands have sent forth, truly then is man ungrateful", romanUrdu: "Ab agar yeh log mooh moadte hain to aey Nabi humne tumko unpar nigehbaan bana kar to nahin bheja hai. Tumpar to sirf baat pahuncha dene ki zimmedari hai.Insaan ka haal yeh hai ke jab hum usey apni rehmat ka maza chakhate hain to uspar phool jata hai. Aur agar uske apne haathon ka kiya dhara kisi musibat ki shakal mein uspar ulat padta hai to sakht na shukra ban jata hai" },
    { number: 49, arabic: "لِّلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ يَخْلُقُ مَا يَشَآءُ ۚ يَهَبُ لِمَن يَشَآءُ إِنَٰثًۭا وَيَهَبُ لِمَن يَشَآءُ ٱلذُّكُورَ", transliteration: "Lillahi mulku alssamawati waalardi yakhluqu ma yashao yahabu liman yashao inathan wayahabu liman yashao alththukoora", transliterationB: "Lillaahi mulkus samaawaati wal ard; yakhluqu maa yashaaa'; yahabu limai yashaaa'u inaasanw wa yahabu limai yashaaa'uz zukoor", english: "To Allah belongs the dominion of the heavens and the earth. He creates what He wills (and plans). He bestows (children) male or female according to His Will (and Plan)", romanUrdu: "Allah zameen aur aasmaano ki baadshahi ka maalik hai. Jo kuch chahta hai paida karta hai. Jisey chahta hai ladkiyan deta hai, jisey chahta hai ladke deta hai" },
    { number: 50, arabic: "أَوْ يُزَوِّجُهُمْ ذُكْرَانًۭا وَإِنَٰثًۭا ۖ وَيَجْعَلُ مَن يَشَآءُ عَقِيمًا ۚ إِنَّهُۥ عَلِيمٌۭ قَدِيرٌۭ", transliteration: "Aw yuzawwijuhum thukranan wainathan wayajAAalu man yashao AAaqeeman innahu AAaleemun qadeerun", transliterationB: "Aw yuzawwijuhum zukraananw wa inaasanw wa yaj'alu mai yashaaa'u 'aqeemaa; innahoo 'Aleemun Qadeer", english: "Or He bestows both males and females, and He leaves barren whom He will: for He is full of Knowledge and Power", romanUrdu: "Jisey chahta hai ladke aur ladkiyan mila-jula kar deta hai aur jisey chahta hai baanjh (barren) kardeta hai. Woh sab kuch jaanta hai aur har cheez par qadir hai" },
    { number: 51, arabic: "۞ وَمَا كَانَ لِبَشَرٍ أَن يُكَلِّمَهُ ٱللَّهُ إِلَّا وَحْيًا أَوْ مِن وَرَآئِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًۭا فَيُوحِىَ بِإِذْنِهِۦ مَا يَشَآءُ ۚ إِنَّهُۥ عَلِىٌّ حَكِيمٌۭ", transliteration: "Wama kana libasharin an yukallimahu Allahu illa wahyan aw min warai hijabin aw yursila rasoolan fayoohiya biithnihi ma yashao innahu AAaliyyun hakeemun", transliterationB: "Wa maa kaana libasharin any yukallimahul laahu illaa wahyan aw minw waraaa'i hijaabin aw yursila Rasoolan fa yoohiya bi iznuhee maa yashaaa'; innahoo 'Aliyyun Hakeem", english: "It is not fitting for a man that Allah should speak to him except by inspiration, or from behind a veil, or by the sending of a messenger to reveal, with Allah's permission, what Allah wills: for He is Most High, Most Wise", romanUrdu: "Kisi bashar (Insaan) ka yeh muqaam nahin hai ke Allah us se ru-baru baat karey, uski baat ya to wahee (isharey/ revelation) ke taur par hoti hai, ya purday ke piche se, ya phir woh koi paigaambar (farishta) bhejta hai aur woh uske hukum se jo kuch woh chahta hai, wahi karta hai. Woh bartar aur Hakeem(wise) hai" },
    { number: 52, arabic: "وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ رُوحًۭا مِّنْ أَمْرِنَا ۚ مَا كُنتَ تَدْرِى مَا ٱلْكِتَٰبُ وَلَا ٱلْإِيمَٰنُ وَلَٰكِن جَعَلْنَٰهُ نُورًۭا نَّهْدِى بِهِۦ مَن نَّشَآءُ مِنْ عِبَادِنَا ۚ وَإِنَّكَ لَتَهْدِىٓ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Wakathalika awhayna ilayka roohan min amrina ma kunta tadree ma alkitabu wala aleemanu walakin jaAAalnahu nooran nahdee bihi man nashao min AAibadina wainnaka latahdee ila siratin mustaqeemin", transliterationB: "Wa kazaalika awhainaaa ilaika rooham min amrinaa; maa kunta tadree mal Kitaabu wa lal eemaanu wa laakin ja'alnaahu nooran nahdee bihee man nashaaa'u min 'ibaadinaa; wa innaka latahdeee ilaaa Siraatim Mustaqeem", english: "And thus have We, by Our Command, sent inspiration to thee: thou knewest not (before) what was Revelation, and what was Faith; but We have made the (Qur'an) a Light, wherewith We guide such of Our servants as We will; and verily thou dost guide (men) to the Straight Way", romanUrdu: "Aur isi tarah (aey Muhammad s.a.s) humne apne hukum se ek rooh tumhari tarf wahee ki hai. Tumhein kuch pata na tha ke kitaab kya hoti hai aur Imaan kya hota hai, Magar us rooh ko humne ek roshni bana diya jissey hum raah dikhate hain apne bandon mein se jisey chahte hain. Yaqeenan tum seedhey raaste ki taraf rehnumayi kar rahey ho" },
    { number: 53, arabic: "صِرَٰطِ ٱللَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ أَلَآ إِلَى ٱللَّهِ تَصِيرُ ٱلْأُمُورُ", transliteration: "Sirati Allahi allathee lahu ma fee alssamawati wama fee alardi ala ila Allahi taseeru alomooru", transliterationB: "Siraatil laahil lazee lahoo maa fis samaawaati wa maa fil ard; alaaa ilal laahi taseerul umoor", english: "The Way of Allah, to Whom belongs whatever is in the heavens and whatever is on earth. Behold (how) all affairs tend towards Allah", romanUrdu: "Us khuda ke raaste ki taraf jo zameen aur aasmaano ki har cheez ka maalik hai. khabardar raho, saarey muaamlaat Allah hi ki taraf rujoo karte hain" }
  ]
};
